def resolve_api_key(self, config_key: str | None = None) -> str | None:
    """Resolve the API key: config override → env var → default."""
    if config_key:
        return config_key
    if self.api_key_env:
        env_val = os.getenv(self.api_key_env)
        if env_val:
            return env_val
    return self.api_key_default
